<?php
/**
 * Preloader — SVG Path Line Drawing Animation
 *
 * Shows the XANH logo with stroke animation on first page load per session.
 * Theme (dark/light) is controlled via ACF settings.
 *
 * Skip conditions (server-side):
 * - Preloader disabled in settings
 * - Single detail pages (post, project, service)
 * - WordPress admin (logged-in + is_admin)
 *
 * Additional skip conditions handled in JS:
 * - sessionStorage (once per session)
 * - prefers-reduced-motion
 * - Slow connection (2g)
 * - Bots/crawlers
 *
 * @package XanhDesignBuild
 * @since   1.0.0
 */

if ( ! defined( 'ABSPATH' ) ) {
	exit;
}

/* ── Server-side skip conditions ── */

// 1. Check ACF setting — enabled?
$preloader_enabled = get_field( 'xanh_preloader_enabled', 'option' );
if ( $preloader_enabled === false || $preloader_enabled === null ) {
	$preloader_enabled = true; // Default: enabled
}
if ( ! $preloader_enabled ) {
	return;
}

// 2. Skip on single detail pages
if ( is_singular( 'post' ) || is_singular( 'xanh_project' ) || is_singular( 'xanh_service' ) ) {
	return;
}

/* ── Theme selection ── */
$preloader_theme = get_field( 'xanh_preloader_theme', 'option' );
if ( ! $preloader_theme ) {
	$preloader_theme = 'dark'; // Default: dark
}

/* ── Display mode: session (once) or always ── */
$preloader_mode = get_field( 'xanh_preloader_mode', 'option' );
if ( ! $preloader_mode ) {
	$preloader_mode = 'session'; // Default: once per session
}

$theme_class = ( $preloader_theme === 'dark' ) ? ' preloader--dark' : '';
?>

